1	import { TrackgenticError } from "../../core/errors";
2	import { Tracker } from "../../core/tracker";
3	import { writeStderr, writeStdout } from "../output";
4	
5	/**
6	 * Handler for the `trackgentic users register <name>` command.
7	 */
8	export async function usersRegisterAction(name: string): Promise<void> {
9	  try {
10	    const tracker = new Tracker();
11	    const result = await tracker.usersRegister(name);
12	    writeStdout(result);
13	    process.exit(0);
14	  } catch (err) {
15	    if (err instanceof TrackgenticError) {
16	      writeStderr({ result: err.result, message: err.message });
17	      process.exit(err.exitCode);
18	    }
19	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
20	    process.exit(1);
21	  }
22	}
