43	/**
44	 * Handler for the `trackgentic users revoke <name>` command.
45	 */
46	export async function usersRevokeAction(name: string): Promise<void> {
47	  try {
48	    const tracker = new Tracker();
49	    const result = await tracker.usersRevoke(name);
50	    if (result instanceof TrackgenticError) {
51	      writeStderr({ result: result.result, message: result.message });
52	      process.exit(result.exitCode);
53	    }
54	    if ("result" in result && result.result !== "OK") {
55	      writeStderr(result);
56	      process.exit(1);
57	    }
58	    writeStdout(result);
59	    process.exit(0);
60	  } catch (err) {
61	    if (err instanceof TrackgenticError) {
62	      writeStderr({ result: err.result, message: err.message });
63	      process.exit(err.exitCode);
64	    }
65	    writeStderr({ result: "INTERNAL_ERROR", message: (err as Error).message });
66	    process.exit(1);
67	  }
68	}
