1	import { existsSync, mkdirSync } from "node:fs";
2	import { join, resolve } from "node:path";
3	import type {
4	  ConfigFile,
5	  CreateParams,
6	  CreateResult,
7	  DependenciesFile,
8	  HistoryResult,
9	  IndexEntry,
10	  IndexFile,
11	  InitResult,
12	  IssueId,
13	  IssueProperties,
14	  IssueStatus,
15	  ListParams,
16	  ListResult,
17	  UpdateParams,
18	  UpdateResult,
19	  UserEntry,
20	  UsersFile,
21	  UsersListResult,
22	  UsersRegenerateResult,
23	  UsersRegisterResult,
24	  UsersRevokeResult,
25	  ViewResult,
26	} from "../types";
27	import { resolveAuthor } from "./auth";
28	import { ErrorCodes, TrackgenticError } from "./errors";
29	import { appendEvent, computeState, replayEvents } from "./events";
30	import { atomicWriteJSON, readJSON } from "./file-io";
31	import { generateId } from "./id";
32	import { findEntry, insertEntry, readIndex, updateEntry, writeIndex } from "./index-manager";
33	import { resolveTrackerDir } from "./resolution";
34	
35	const TRACKGENTIC_DIR = ".trackgentic";
36	
37	/**
38	 * Default config.json contents.
39	 */
40	const DEFAULT_CONFIG: ConfigFile = {
41	  auth: {
42	    mode: "open",
43	    defaultUser: "anonymous",
44	  },
45	};
46	
47	/**
48	 * Default index.json contents.
49	 */
50	const DEFAULT_INDEX: IndexFile = {
51	  open: [],
52	  closed: [],
53	  childrenOf: {},
54	};
55	
56	/**
57	 * Default dependencies.json contents.
58	 */
59	const DEFAULT_DEPENDENCIES: DependenciesFile = {
60	  blockedBy: {},
61	  blocks: {},
62	};
63	
64	/**
65	 * Default users.json contents.
66	 */
67	const DEFAULT_USERS: UsersFile = {
68	  users: [],
69	};
70	
71	/**
72	 * Generate a token: tk_ + 8 random alphanumeric characters.
73	 */
74	function generateToken(): string {
75	  return `tk_${Math.random().toString(36).slice(2, 10)}`;
76	}
77	
78	/**
79	 * Tracker — the main programmatic API for trackgentic.
80	 *
81	 * The constructor accepts a `cwd` parameter (defaults to `process.cwd()`).
82	 * It does NOT validate that `.trackgentic/` exists — resolution happens on each method call.
83	 */
84	export class Tracker {
85	  private cwd: string;
86	
87	  constructor(cwd?: string) {
88	    this.cwd = cwd ?? process.cwd();
89	  }
90	
91	  /**
92	   * Initialize a new `.trackgentic/` directory in `cwd`.
93	   */
94	  async init(): Promise<InitResult> {
95	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
96	
97	    if (existsSync(trackerDir)) {
98	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
99	    }
100	
101	    mkdirSync(trackerDir, { recursive: true });
102	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
103	
104	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
105	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
106	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
107	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
108	
109	    return { result: "OK", path: resolve(trackerDir) };
110	  }
111	
112	  /**
113	   * Create a new issue.
114	   */
115	  async create(params: CreateParams): Promise<CreateResult> {
116	    const trackerDir = resolveTrackerDir(this.cwd);
117	    if (!trackerDir) {
118	      throw new TrackgenticError(
119	        ErrorCodes.NOT_INITIALIZED.result,
120	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
121	        ErrorCodes.NOT_INITIALIZED.exitCode,
122	      );
123	    }
124	
125	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
126	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
127	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
128	    if (authResult instanceof TrackgenticError) return authResult;
129	    const author = params.author ?? authResult.author;
130	
131	    const id = generateId();
132	    const issuePath = params.path ?? `issues/${id}.json`;
133	    const now = new Date().toISOString();
134	
135	    const title = params.title;
136	    const description = params.description ?? "";
137	    const status: IssueStatus = params.status ?? "idea";
138	    const priority = params.priority ?? 3;
139	    const assignee = params.assignee ?? null;
140	    const parentId = params.parentId ?? null;
141	    const tags = params.tags ?? [];
142	
143	    // Build update content with only non-default values
144	    const updateContent: Partial<
145	      Pick<
146	        IssueProperties,
147	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
148	      >
149	    > & { title: string } = { title };
150	    if (description) updateContent.description = description;
151	    if (status !== "idea") updateContent.status = status;
152	    if (priority !== 3) updateContent.priority = priority;
153	    if (assignee !== null) updateContent.assignee = assignee;
154	    if (parentId !== null) updateContent.parentId = parentId;
155	    if (tags.length > 0) updateContent.tags = tags;
156	
157	    // Create issue file with two events: creation + update
158	    const creationEvent = { type: "creation" as const, timestamp: now, author };
159	    const updateEvent = {
160	      type: "update" as const,
161	      timestamp: now,
162	      author,
163	      content: updateContent,
164	    };
165	
166	    const issueFilePath = join(trackerDir, issuePath);
167	    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);
168	
169	    // Build index entry and insert into index
170	    const entry: IndexEntry = {
171	      id,
172	      title,
173	      path: issuePath,
174	      status,
175	      assignee,
176	      parentId,
177	      tags,
178	      priority,
179	    };
180	
181	    const index = await readIndex(trackerDir);
182	    const updatedIndex = insertEntry(index, entry);
183	    await writeIndex(trackerDir, updatedIndex);
184	
185	    return { id };
186	  }
187	
188	  /**
189	   * List issues from the index, with optional filters.
190	   */
191	  async list(params?: ListParams): Promise<ListResult> {
192	    const trackerDir = resolveTrackerDir(this.cwd);
193	    if (!trackerDir) {
194	      throw new TrackgenticError(
195	        ErrorCodes.NOT_INITIALIZED.result,
196	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
197	        ErrorCodes.NOT_INITIALIZED.exitCode,
198	      );
199	    }
200	
201	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
202	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
203	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
204	    if (authResult instanceof TrackgenticError) {
205	      throw authResult;
206	    }
207	
208	    const index = await readIndex(trackerDir);
209	
210	    // Determine source arrays based on params.status
211	    let entries: IndexEntry[];
212	    if (params?.status === "closed") {
213	      entries = index.closed;
214	    } else if (params?.status === "open") {
215	      entries = index.open;
216	    } else if (params?.status) {
217	      entries = index.open;
218	    } else {
219	      entries = [...index.open, ...index.closed];
220	    }
221	
222	    // Filter in memory
223	    let filtered = entries;
224	
225	    if (params?.status && params.status !== "open" && params.status !== "closed") {
226	      filtered = filtered.filter((e) => e.status === params.status);
227	    }
228	
229	    if (params?.assignee) {
230	      filtered = filtered.filter((e) => e.assignee === params.assignee);
231	    }
232	
233	    if (params?.tags && params.tags.length > 0) {
234	      filtered = filtered.filter((e) => params.tags?.every((tag) => e.tags.includes(tag)));
235	    }
236	
237	    if (params?.parentId !== undefined) {
238	      if (params.parentId === null) {
239	        filtered = filtered.filter((e) => e.parentId === null);
240	      } else {
241	        filtered = filtered.filter((e) => e.parentId === params.parentId);
242	      }
243	    }
244	
245	    // Sort: priority ASC → id ASC
246	    filtered.sort((a, b) => {
247	      if (a.priority !== b.priority) return a.priority - b.priority;
248	      return a.id.localeCompare(b.id);
249	    });
250	
251	    return filtered;
252	  }
253	
254	  /**
255	   * View a single issue's full computed state.
256	   */
257	  async view(id: IssueId): Promise<ViewResult> {
258	    const trackerDir = resolveTrackerDir(this.cwd);
259	    if (!trackerDir) {
260	      throw new TrackgenticError(
261	        ErrorCodes.NOT_INITIALIZED.result,
262	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
263	        ErrorCodes.NOT_INITIALIZED.exitCode,
264	      );
265	    }
266	
267	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
268	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
269	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
270	    if (authResult instanceof TrackgenticError) {
271	      throw authResult;
272	    }
273	
274	    const index = await readIndex(trackerDir);
275	    const entry = findEntry(index, id);
276	    if (!entry) {
277	      throw new TrackgenticError(
278	        ErrorCodes.NOT_FOUND.result,
279	        `Issue ${id} not found in index.`,
280	        ErrorCodes.NOT_FOUND.exitCode,
281	      );
282	    }
283	
284	    const issueFilePath = join(trackerDir, entry.path);
285	    if (!existsSync(issueFilePath)) {
286	      throw new TrackgenticError(
287	        ErrorCodes.ISSUE_MISSING.result,
288	        `Issue file for ${id} is missing.`,
289	        ErrorCodes.ISSUE_MISSING.exitCode,
290	      );
291	    }
292	
293	    const events = await replayEvents(issueFilePath);
294	    return computeState(events, id);
295	  }
296	
297	  /**
298	   * Update an existing issue.
299	   */
300	  async update(id: IssueId, params: UpdateParams): Promise<UpdateResult> {
301	    const trackerDir = resolveTrackerDir(this.cwd);
302	    if (!trackerDir) {
303	      throw new TrackgenticError(
304	        ErrorCodes.NOT_INITIALIZED.result,
305	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
306	        ErrorCodes.NOT_INITIALIZED.exitCode,
307	      );
308	    }
309	
310	    // Validate at least one field provided (besides author)
311	    const hasField =
312	      params.title !== undefined ||
313	      params.description !== undefined ||
314	      params.status !== undefined ||
315	      params.assignee !== undefined ||
316	      params.tags !== undefined ||
317	      params.priority !== undefined ||
318	      params.parentId !== undefined;
319	
320	    if (!hasField) {
321	      throw new TrackgenticError(
322	        ErrorCodes.INVALID_PARAMS.result,
323	        "At least one field must be provided for update.",
324	        ErrorCodes.INVALID_PARAMS.exitCode,
325	      );
326	    }
327	
328	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
329	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
330	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
331	    if (authResult instanceof TrackgenticError) return authResult;
332	    const author = params.author ?? authResult.author;
333	
334	    const index = await readIndex(trackerDir);
335	    const entry = findEntry(index, id);
336	    if (!entry) {
337	      throw new TrackgenticError(
338	        ErrorCodes.NOT_FOUND.result,
339	        `Issue ${id} not found in index.`,
340	        ErrorCodes.NOT_FOUND.exitCode,
341	      );
342	    }
343	
344	    const issueFilePath = join(trackerDir, entry.path);
345	    if (!existsSync(issueFilePath)) {
346	      throw new TrackgenticError(
347	        ErrorCodes.ISSUE_MISSING.result,
348	        `Issue file for ${id} is missing.`,
349	        ErrorCodes.ISSUE_MISSING.exitCode,
350	      );
351	    }
352	
353	    // Build update event content with only the provided fields
354	    const content: Partial<
355	      Pick<
356	        IssueProperties,
357	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
358	      >
359	    > = {};
360	    if (params.title !== undefined) content.title = params.title;
361	    if (params.description !== undefined) content.description = params.description;
362	    if (params.status !== undefined) content.status = params.status;
363	    if (params.assignee !== undefined) content.assignee = params.assignee;
364	    if (params.tags !== undefined) content.tags = params.tags;
365	    if (params.priority !== undefined) content.priority = params.priority;
366	    if (params.parentId !== undefined) content.parentId = params.parentId;
367	
368	    const now = new Date().toISOString();
369	
370	    const updateEvent = {
371	      type: "update" as const,
372	      timestamp: now,
373	      author,
374	      content,
375	    };
376	
377	    // Append event to issue file
378	    await appendEvent(issueFilePath, updateEvent);
379	
380	    // Recompute state from all events
381	    const events = await replayEvents(issueFilePath);
382	    const computed = computeState(events, id);
383	
384	    // Update index entry with new computed values
385	    const updatedIndex = updateEntry(index, id, {
386	      title: computed.title,
387	      status: computed.status,
388	      assignee: computed.assignee,
389	      parentId: computed.parentId,
390	      tags: computed.tags,
391	      priority: computed.priority,
392	    });
393	
394	    await writeIndex(trackerDir, updatedIndex);
395	
396	    return { result: "OK" };
397	  }
398	
399	  /**
400	   * Get the raw event history for an issue.
401	   */
402	  async history(id: IssueId): Promise<HistoryResult> {
403	    const trackerDir = resolveTrackerDir(this.cwd);
404	    if (!trackerDir) {
405	      throw new TrackgenticError(
406	        ErrorCodes.NOT_INITIALIZED.result,
407	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
408	        ErrorCodes.NOT_INITIALIZED.exitCode,
409	      );
410	    }
411	
412	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
413	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
414	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
415	    if (authResult instanceof TrackgenticError) {
416	      throw authResult;
417	    }
418	
419	    const index = await readIndex(trackerDir);
420	    const entry = findEntry(index, id);
421	    if (!entry) {
422	      throw new TrackgenticError(
423	        ErrorCodes.NOT_FOUND.result,
424	        `Issue ${id} not found in index.`,
425	        ErrorCodes.NOT_FOUND.exitCode,
426	      );
427	    }
428	
429	    const issueFilePath = join(trackerDir, entry.path);
430	    if (!existsSync(issueFilePath)) {
431	      throw new TrackgenticError(
432	        ErrorCodes.ISSUE_MISSING.result,
433	        `Issue file for ${id} is missing.`,
434	        ErrorCodes.ISSUE_MISSING.exitCode,
435	      );
436	    }
437	
438	    return replayEvents(issueFilePath);
