441	  // ─── User Management ──────────────────────────────────────────────
442	
443	  /**
444	   * Register a new user. Does NOT require auth (bootstrap mechanism).
445	   */
446	  async usersRegister(name: string): Promise<UsersRegisterResult> {
447	    const trackerDir = resolveTrackerDir(this.cwd);
448	    if (!trackerDir) {
449	      throw new TrackgenticError(
450	        ErrorCodes.NOT_INITIALIZED.result,
451	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
452	        ErrorCodes.NOT_INITIALIZED.exitCode,
453	      );
454	    }
455	
456	    const lowerName = name.toLowerCase();
457	
458	    // Reject reserved name
459	    if (lowerName === "anonymous") {
460	      return {
461	        result: "USER_ALREADY_EXISTS",
462	        message: `"anonymous" is a reserved name and cannot be registered.`,
463	      };
464	    }
465	
466	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
467	
468	    // Check uniqueness
469	    if (users.users.find((u) => u.name === lowerName)) {
470	      return {
471	        result: "USER_ALREADY_EXISTS",
472	        message: `User "${lowerName}" already exists.`,
473	      };
474	    }
475	
476	    const token = generateToken();
477	    const newUser: UserEntry = {
478	      name: lowerName,
479	      token,
480	      registeredAt: new Date().toISOString(),
481	    };
482	
483	    users.users.push(newUser);
484	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
485	
486	    return { result: "OK", name: lowerName, token };
487	  }
488	
489	  /**
490	   * List all registered users (tokens stripped).
491	   * Auth: depends on mode (read operation).
492	   */
493	  async usersList(): Promise<UsersListResult> {
494	    const trackerDir = resolveTrackerDir(this.cwd);
495	    if (!trackerDir) {
496	      throw new TrackgenticError(
497	        ErrorCodes.NOT_INITIALIZED.result,
498	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
499	        ErrorCodes.NOT_INITIALIZED.exitCode,
500	      );
501	    }
502	
503	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
504	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
505	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
506	    if (authResult instanceof TrackgenticError) {
507	      throw authResult;
508	    }
509	
