516	  /**
517	   * Revoke (remove) a user. Requires auth (write operation).
518	   */
519	  async usersRevoke(name: string): Promise<UsersRevokeResult> {
520	    const trackerDir = resolveTrackerDir(this.cwd);
521	    if (!trackerDir) {
522	      throw new TrackgenticError(
523	        ErrorCodes.NOT_INITIALIZED.result,
524	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
525	        ErrorCodes.NOT_INITIALIZED.exitCode,
526	      );
527	    }
528	
529	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
530	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
531	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
532	    if (authResult instanceof TrackgenticError) {
533	      throw authResult;
534	    }
535	
536	    const lowerName = name.toLowerCase();
537	    const userIndex = users.users.findIndex((u) => u.name === lowerName);
538	    if (userIndex === -1) {
539	      return {
540	        result: "USER_NOT_FOUND",
541	        message: `User "${lowerName}" not found.`,
542	      };
543	    }
544	
545	    users.users.splice(userIndex, 1);
546	    await atomicWriteJSON(join(trackerDir, "users.json"), users);
547	
548	    return { result: "OK" };
549	  }
